// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  const isSmall = width < 420;
  const isMobile = width < 768;
  const isDesktop = width >= 1024;

  // centered like the mockup
  const containerMaxWidth = isDesktop ? 560 : isMobile ? 560 : "100%";

  const [query, setQuery] = useState("Total borne 10 entre\nenfant noir chez le boss");

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      {/* ✅ no ScrollView: screen must not scroll */}
      <View style={styles.page}>
        {/* Big rounded shell like mockup */}
        <View style={[styles.shell, { maxWidth: containerMaxWidth }]}>
          {/* Header */}
          <View style={styles.headerRow}>
            <Image
              source={nalicoreLogo}
              style={[styles.logo, { width: isSmall ? 200 : 240 }]}
              resizeMode="contain"
            />
            <Text
              style={[
                styles.tagline,
                {
                  fontSize: isSmall ? 15 : 16,
                  lineHeight: isSmall ? 19 : 22,
                },
              ]}
              numberOfLines={2}
            >
              Natural{"\n"}Address
            </Text>
          </View>

          {/* Search + Resolve */}
          <View style={styles.searchBar}>
            <View style={styles.searchLeft}>
              <Text style={styles.searchIcon}>⌕</Text>

              <TextInput
                value={query}
                onChangeText={setQuery}
                style={[
                  styles.searchInput,
                  {
                    fontSize: isSmall ? 16 : 18,
                    lineHeight: isSmall ? 20 : 24,
                  },
                ]}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                // ✅ critical: web should NOT be multiline (looks like textarea)
                multiline={Platform.OS !== "web"}
                scrollEnabled={false}
                textAlignVertical="center"
                underlineColorAndroid="transparent"
              />
            </View>

            <View style={styles.searchDivider} />

            <TouchableOpacity
              activeOpacity={0.92}
              style={[styles.resolveBtn, { width: isSmall ? 140 : 160 }]}
              onPress={onResolve}
            >
              <Text style={[styles.resolveText, { fontSize: isSmall ? 16 : 18 }]}>
                Resolve
              </Text>
            </TouchableOpacity>
          </View>

          {/* Resolved card */}
          <View style={styles.card}>
            <View style={styles.cardHeaderStrip}>
              <Text style={[styles.cardTitle, { fontSize: isSmall ? 22 : 24 }]}>
                Resolved Address
              </Text>
            </View>

            <View style={styles.cardBody}>
              <Row label="Quartier:" value={resolved.quartier} isSmall={isSmall} />
              <Row label="Secteur:" value={resolved.secteur} isSmall={isSmall} />
              <Row
                label="Sous-secteur:"
                value={resolved.sousSecteur}
                isSmall={isSmall}
              />
              <Row label="Entrée:" value={resolved.entree} isSmall={isSmall} />
              <Row label="Lieu:" value={resolved.lieu} isSmall={isSmall} />

              <View style={styles.row}>
                <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>
                  BANOC:
                </Text>
                <View style={styles.banocPill}>
                  <Text style={styles.banocText}>{resolved.banoc}</Text>
                </View>
              </View>

              {/* ✅ GPS removed */}
              <Row
                label="Latitude:"
                value={Number(resolved.latitude).toFixed(5)}
                isSmall={isSmall}
              />
              <Row
                label="Longitude:"
                value={Number(resolved.longitude).toFixed(5)}
                isSmall={isSmall}
              />

              <TouchableOpacity
                activeOpacity={0.92}
                style={styles.navBtn}
                onPress={onNavigate}
              >
                <View style={styles.pinWrap}>
                  <PinIcon />
                </View>
                <Text style={[styles.navText, { fontSize: isSmall ? 18 : 19 }]}>
                  Navigate to Location
                </Text>
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </View>
    </SafeAreaView>
  );
}

function Row({ label, value, isSmall }) {
  return (
    <View style={styles.row}>
      <Text style={[styles.label, { fontSize: isSmall ? 14 : 15 }]}>{label}</Text>
      <Text
        style={[styles.value, { fontSize: isSmall ? 15 : 16 }]}
        numberOfLines={1}
        ellipsizeMode="tail"
      >
        {value}
      </Text>
    </View>
  );
}

function PinIcon() {
  return (
    <View style={styles.pinCircle}>
      <View style={styles.pinHead} />
      <View style={styles.pinStem} />
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },

  page: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    paddingHorizontal: 16,
    paddingVertical: 14,
  },

  // outer rounded panel like mockup
  shell: {
    width: "100%",
    borderRadius: 34,
    paddingHorizontal: 22,
    paddingTop: 26,
    paddingBottom: 26,
    backgroundColor: "rgba(255,255,255,0.45)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    ...Platform.select({
      ios: {
        shadowColor: "#0B1020",
        shadowOpacity: 0.10,
        shadowRadius: 30,
        shadowOffset: { width: 0, height: 22 },
      },
      android: { elevation: 5 },
    }),
  },

  headerRow: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    gap: 14,
    marginBottom: 18,
  },

  logo: { height: 54 },

  tagline: {
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.60)",
    fontWeight: "600",
    maxWidth: 180,
  },

  searchBar: {
    width: "100%",
    height: 74,
    borderRadius: 18,
    overflow: "hidden",
    flexDirection: "row",
    backgroundColor: "rgba(255,255,255,0.55)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.10)",
    marginBottom: 18,
    ...Platform.select({
      ios: {
        shadowColor: "#0B1020",
        shadowOpacity: 0.07,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 2 },
    }),
  },

  // ✅ IMPORTANT: minWidth:0 fixes clipping on web
  searchLeft: {
    flex: 1,
    minWidth: 0,
    paddingLeft: 52,
    paddingRight: 12,
    justifyContent: "center",
  },

  searchIcon: {
    position: "absolute",
    left: 18,
    top: 28,
    fontSize: 20,
    color: "rgba(15, 23, 42, 0.45)",
  },

  searchInput: {
    flex: 1,
    minWidth: 0,
    fontWeight: "700",
    color: "#0F172A",
    height: "100%",
    paddingVertical: 0,
